class NoArvore {
  constructor(valor) {
    this.valor = valor;
    this.esq = null;
    this.dir = null;
  }
}

class BST {
  constructor() { this.raiz = null; }

  inserir(valor) {
    const inserirRec = (no, v) => {
      if (!no) return new NoArvore(v);
      if (v < no.valor) no.esq = inserirRec(no.esq, v);
      else if (v > no.valor) no.dir = inserirRec(no.dir, v);
      return no;
    };
    this.raiz = inserirRec(this.raiz, valor);
  }

  buscar(valor) {
    const buscarRec = (no, v) => {
      if (!no || no.valor === v) return no;
      return v < no.valor
        ? buscarRec(no.esq, v)
        : buscarRec(no.dir, v);
    };
    return buscarRec(this.raiz, valor);
  }
}

