function parentesesBalanceados(str) {
  const pilha = new Pilha();
  const pares = { ')': '(', ']': '[', '}': '{' };

  for (const char of str) {
    if ('([{'.includes(char)) pilha.push(char);
    else if (')]}'.includes(char)) {
      if (pilha.vazia() || pilha.pop() !== pares[char]) return false;
    }
  }
  return pilha.vazia();
