#include <stdio.h>
#include <stdlib.h>
#define MAX 100

/* PILHA COM ARRAY */
typedef struct {
    int dados[MAX];
    int topo;
} Pilha;

void inicializar(Pilha* p) { p->topo = -1; }

void push(Pilha* p, int valor) {
    if (p->topo >= MAX - 1) { printf("Pilha cheia!\n"); return; }
    p->dados[++p->topo] = valor;
}

int pop(Pilha* p) {
    if (p->topo == -1) { printf("Pilha vazia!\n"); return -1; }
    return p->dados[p->topo--];
}

int topo(Pilha* p) { return p->dados[p->topo]; }

int main() {
    Pilha p;
    inicializar(&p);
    push(&p, 10);
    push(&p, 20);
    push(&p, 30);
    printf("Topo: %d\n", topo(&p)); // 30
    printf("Pop: %d\n", pop(&p));   // 30
    printf("Pop: %d\n", pop(&p));   // 20
    return 0;
}

