// ===== FILA COM LISTA ENCADEADA (O(1) em ambas operações) =====
class No {
  constructor(valor) { this.valor = valor; this.proximo = null; }
}

class Fila {
  constructor() { this.inicio = null; this.fim = null; this.tamanho = 0; }

  enqueue(valor) {
    const no = new No(valor);
    if (!this.fim) { this.inicio = this.fim = no; }
    else { this.fim.proximo = no; this.fim = no; }
    this.tamanho++;
  }

  dequeue() {
    if (!this.inicio) throw new Error('Fila vazia');
    const val = this.inicio.valor;
    this.inicio = this.inicio.proximo;
    if (!this.inicio) this.fim = null;
    this.tamanho--;
    return val;
  }

  frente() { return this.inicio?.valor; }
  vazia() { return this.tamanho === 0; }
}

// ===== CASO DE USO: BFS em grafo =====
function bfs(grafo, inicio) {
  const visitado = new Set([inicio]);
  const fila = new Fila();
  fila.enqueue(inicio);

  while (!fila.vazia()) {
    const no = fila.dequeue();
    console.log('Visitando:', no);

    for (const vizinho of grafo[no] || []) {
      if (!visitado.has(vizinho)) {
        visitado.add(vizinho);
        fila.enqueue(vizinho);
      }
    }
  }
}

