#include <stdio.h>
#include <stdlib.h>
#define MAX 100

/* FILA COM ARRAY CIRCULAR */
typedef struct {
    int dados[MAX];
    int inicio, fim, tamanho;
} Fila;

void inicializar(Fila* f) { f->inicio = f->fim = f->tamanho = 0; }

void enqueue(Fila* f, int valor) {
    if (f->tamanho == MAX) { printf("Fila cheia!\n"); return; }
    f->dados[f->fim] = valor;
    f->fim = (f->fim + 1) % MAX;  /* circular! */
    f->tamanho++;
}

int dequeue(Fila* f) {
    if (f->tamanho == 0) { printf("Fila vazia!\n"); return -1; }
    int val = f->dados[f->inicio];
    f->inicio = (f->inicio + 1) % MAX; /* circular! */
    f->tamanho--;
    return val;
}

int main() {
    Fila f;
    inicializar(&f);
    enqueue(&f, 10);
    enqueue(&f, 20);
    enqueue(&f, 30);
    printf("%d\n", dequeue(&f)); // 10 (FIFO)
    printf("%d\n", dequeue(&f)); // 20
    return 0;
}

