// ===== FILA MANUAL COM LISTA ENCADEADA =====
class Fila<T> {
    private static class No<T> {
        T valor; No<T> proximo;
        No(T v) { valor = v; }
    }

    private No<T> inicio, fim;
    private int tamanho;

    void enqueue(T valor) {
        No<T> no = new No<>(valor);
        if (fim == null) { inicio = fim = no; }
        else { fim.proximo = no; fim = no; }
        tamanho++;
    }

    T dequeue() {
        T val = inicio.valor;
        inicio = inicio.proximo;
        if (inicio == null) fim = null;
        tamanho--;
        return val;
    }
}

