// ===== ANATOMIA DA RECURSÃO =====
function fatorial(n) {
  // 1. CASO BASE: condição de parada
  if (n <= 1) return 1;
  // 2. CASO RECURSIVO: reduz o problema
  return n * fatorial(n - 1);
}
// fatorial(5) = 5 * fatorial(4)
//             = 5 * 4 * fatorial(3)
//             = 5 * 4 * 3 * fatorial(2)
//             = 5 * 4 * 3 * 2 * fatorial(1)
//             = 5 * 4 * 3 * 2 * 1 = 120

// ===== FIBONACCI (ingênuo vs memoization) =====
// Ingênuo: O(2^n) — MUITO LENTO
function fibLento(n) {
  if (n <= 1) return n;
  return fibLento(n - 1) + fibLento(n - 2);
}

// Com memoization: O(n) — eficiente!
function fib(n, memo = new Map()) {
  if (n <= 1) return n;
  if (memo.has(n)) return memo.get(n); // cache!
  const resultado = fib(n - 1, memo) + fib(n - 2, memo);
  memo.set(n, resultado);
  return resultado;
}
console.log(fib(50)); // 12586269025 — instantâneo!

// ===== PERCORRER ÁRVORE (DFS recursivo) =====
function somarArvore(no) {
  if (!no) return 0; // caso base: nó nulo
  return no.valor + somarArvore(no.esq) + somarArvore(no.dir);
}

// ===== MERGE SORT: divide e conquista =====
function mergeSort(arr) {
  if (arr.length <= 1) return arr; // caso base
  const meio = Math.floor(arr.length / 2);
  const esq = mergeSort(arr.slice(0, meio));  // recursão
  const dir = mergeSort(arr.slice(meio));      // recursão
  return merge(esq, dir);                      // combina
}

function merge(esq, dir) {
  const resultado = [];
  let i = 0, j = 0;
  while (i < esq.length && j < dir.length) {
    resultado.push(esq[i] <= dir[j] ? esq[i++] : dir[j++]);
  }
  return [...resultado, ...esq.slice(i), ...dir.slice(j)];
}
console.log(mergeSort([5,2,8,1,9,3])); // [1,2,3,5,8,9]

