def busca_binaria(arr, alvo, inicio=0, fim=None):
    if fim is None: fim = len(arr) - 1
    if inicio > fim: return -1         # caso base: não encontrou

    meio = (inicio + fim) // 2
    if arr[meio] == alvo: return meio  # caso base: encontrou!
    elif arr[meio] < alvo:
        return busca_binaria(arr, alvo, meio + 1, fim)  # direita
    else:
        return busca_binaria(arr, alvo, inicio, meio - 1)  # esquerda

