/* FATORIAL */
long long fatorial(int n) {
    if (n <= 1) return 1;           /* caso base */
    return n * fatorial(n - 1);     /* caso recursivo */
}

/* FIBONACCI COM MEMOIZATION */
#define MAX 100
long long memo[MAX];

long long fib(int n) {
    if (n <= 1) return n;
    if (memo[n] != -1) return memo[n];  /* cache */
    memo[n] = fib(n-1) + fib(n-2);
    return memo[n];
}

/* POTÊNCIA RECURSIVA (divide e conquista) */
long long potencia(long long base, int exp) {
    if (exp == 0) return 1;           /* caso base */
    if (exp % 2 == 0) {
        long long metade = potencia(base, exp / 2);
        return metade * metade;        /* O(log n)! */
    }
    return base * potencia(base, exp - 1);
}

int main() {
    /* inicializa memo */
    for (int i = 0; i < MAX; i++) memo[i] = -1;

    printf("5! = %lld\n", fatorial(5));     /* 120 */
    printf("fib(10) = %lld\n", fib(10));    /* 55 */
    printf("2^10 = %lld\n", potencia(2, 10)); /* 1024 */
    return 0;
}

