// ===== TORRES DE HANÓI =====
public class Recursao {

    // Mover n discos da haste origem para destino usando auxiliar
    static void hanoi(int n, char origem, char destino, char auxiliar) {
        if (n == 1) {  // caso base
            System.out.printf("Mover disco 1: %c → %c%n", origem, destino);
            return;
        }
        hanoi(n - 1, origem, auxiliar, destino);  // move n-1 para auxiliar
        System.out.printf("Mover disco %d: %c → %c%n", n, origem, destino);
        hanoi(n - 1, auxiliar, destino, origem);  // move n-1 para destino
    }

    // ===== MERGE SORT =====
    static int[] mergeSort(int[] arr) {
        if (arr.length <= 1) return arr;
        int meio = arr.length / 2;
        int[] esq = mergeSort(java.util.Arrays.copyOfRange(arr, 0, meio));
        int[] dir = mergeSort(java.util.Arrays.copyOfRange(arr, meio, arr.length));
        return merge(esq, dir);
    }

    static int[] merge(int[] a, int[] b) {
        int[] res = new int[a.length + b.length];
        int i = 0, j = 0, k = 0;
        while (i < a.length && j < b.length)
            res[k++] = a[i] <= b[j] ? a[i++] : b[j++];
        while (i < a.length) res[k++] = a[i++];
        while (j < b.length) res[k++] = b[j++];
        return res;
    }

    public static void main(String[] args) {
        hanoi(3, 'A', 'C', 'B');  // Torres de Hanói com 3 discos
    }
}

