// Testando um componente React com RTL
import { render, screen, fireEvent, waitFor } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { BotaoLogin } from './BotaoLogin';

describe('BotaoLogin', () => {
  it('mostra spinner ao clicar e mensagem de sucesso', async () => {
    const mockLogin = jest.fn().mockResolvedValue({ ok: true });
    render(<BotaoLogin onLogin={mockLogin} />);

    // Encontra pelo texto visível (como o usuário vê)
    const btn = screen.getByRole('button', { name: /entrar/i });
    await userEvent.click(btn);

    // Verifica loading
    expect(screen.getByText(/carregando/i)).toBeInTheDocument();

    // Aguarda resultado assíncrono
    await waitFor(() => {
      expect(screen.getByText(/bem-vindo/i)).toBeInTheDocument();
    });
    expect(mockLogin).toHaveBeenCalledTimes(1);
  });

  it('exibe erro quando login falha', async () => {
    const mockLogin = jest.fn().mockRejectedValue(new Error('Credenciais inválidas'));
    render(<BotaoLogin onLogin={mockLogin} />);
    await userEvent.click(screen.getByRole('button', { name: /entrar/i }));
    await waitFor(() => {
      expect(screen.getByRole('alert')).toHaveTextContent(/credenciais inválidas/i);
    });
  });
});
